package main

import (
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"
)

// allowedHosts is a whitelist of permitted partner API domains
var allowedHosts = map[string]bool{
	"api.partner1.com": true,
	"api.partner2.com": true,
	"api.partner3.com": true,
}

func webhookProxyHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet && r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "Missing 'url' query parameter", http.StatusBadRequest)
		return
	}

	// Parse and validate the URL
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		http.Error(w, "Invalid URL", http.StatusBadRequest)
		return
	}

	// Ensure the scheme is HTTPS only
	if parsedURL.Scheme != "https" {
		http.Error(w, "Only HTTPS URLs are allowed", http.StatusBadRequest)
		return
	}

	// Normalize the hostname
	hostname := strings.ToLower(parsedURL.Hostname())

	// Check against the allowlist of partner API hosts
	if !allowedHosts[hostname] {
		http.Error(w, "Host not in allowed list", http.StatusForbidden)
		return
	}

	// Reject URLs with user info (e.g., user:pass@host) to prevent credential leakage
	if parsedURL.User != nil {
		http.Error(w, "URLs with user info are not allowed", http.StatusBadRequest)
		return
	}

	// Use a client with a timeout to prevent hanging connections
	client := &http.Client{
		Timeout: 10 * time.Second,
		// Prevent following redirects to non-allowed hosts
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			redirectHost := strings.ToLower(req.URL.Hostname())
			if !allowedHosts[redirectHost] {
				return fmt.Errorf("redirect to non-allowed host: %s", redirectHost)
			}
			if req.URL.Scheme != "https" {
				return fmt.Errorf("redirect to non-HTTPS URL")
			}
			if len(via) >= 3 {
				return fmt.Errorf("too many redirects")
			}
			return nil
		},
	}

	// Reconstruct the URL from parsed components to avoid injection
	sanitizedURL := parsedURL.String()

	resp, err := client.Get(sanitizedURL)
	if err != nil {
		http.Error(w, "Failed to fetch URL", http.StatusBadGateway)
		return
	}
	defer resp.Body.Close()

	// Limit the response body size to prevent memory exhaustion (10 MB)
	const maxBodySize = 10 * 1024 * 1024
	limitedReader := io.LimitReader(resp.Body, maxBodySize)

	// Copy safe response headers
	contentType := resp.Header.Get("Content-Type")
	if contentType != "" {
		w.Header().Set("Content-Type", contentType)
	}

	// Set security headers
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("X-Frame-Options", "DENY")
	w.Header().Set("Content-Security-Policy", "default-src 'none'")

	w.WriteHeader(resp.StatusCode)

	_, err = io.Copy(w, limitedReader)
	if err != nil {
		// Response already started, can't send error status
		return
	}
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/proxy", webhookProxyHandler)

	server := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	fmt.Println("Webhook proxy server starting on :8080")
	if err := server.ListenAndServe(); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}